// Obtener mensaje normalizado — soporta ruta chat y webhook
let normalized;
try {
  normalized = $('Normalizar Mensaje Chat').first().json;
} catch(e) {
  normalized = $('Normalizar Mensaje').first().json;
}

// Sesión — respuesta paginada DRF: { count, results: [...] }
let sessionObj = {};
let session_id = null;
try {
  const raw = $('Cargar Sesion').first().json;
  const results = raw.results || (Array.isArray(raw) ? raw : (raw.id ? [raw] : []));
  if (results.length > 0 && results[0].id) {
    sessionObj = results[0];
    session_id = results[0].id;
  }
} catch(e) {}

// Reminder pendiente — respuesta paginada DRF
let reminder = {};
try {
  const raw = $('Verificar Reminder Pendiente').first().json;
  const results = raw.results || (Array.isArray(raw) ? raw : (raw.id ? [raw] : []));
  if (results.length > 0 && results[0].id) {
    reminder = results[0];
  }
} catch(e) {}

// Paciente — determinar si es nuevo y obtener su nombre real
let is_new_patient = false;
let patient_name = '';
try {
  const raw = $('Buscar Paciente').first().json;
  const results = raw.results || (Array.isArray(raw) ? raw : (raw.id ? [raw] : []));
  if (results.length > 0 && results[0].id) {
    is_new_patient = false;
    patient_name = (results[0].first_name || '') + ' ' + (results[0].last_name || '');
    patient_name = patient_name.trim();
  } else {
    is_new_patient = true;
  }
} catch(e) {
  is_new_patient = true;
}

// Guardar phone para el error
$execution.customData.set('phone', normalized.phone)

return [{ json: {
  chatInput: normalized.message,
  phone: normalized.phone,
  clinic_id: normalized.clinic_id || 'default',
  phone_number_id: normalized.phone_number_id || 'test',
  contact_name: normalized.contact_name || 'Usuario Chat',
  session_id: session_id,
  session_data: JSON.stringify(sessionObj.session_data || {}),
  is_reminder_response: !!(reminder && reminder.id),
  pending_appointment_id: reminder.id || '',
  pending_appointment_service: reminder.service || '',
  pending_appointment_datetime: reminder.scheduled_at || '',
  is_new_patient: is_new_patient,
  patient_name: patient_name
}}];

return [{ json: {
  success: false,
  message: 'Disculpa, tuve un problema tecnico. Por favor intenta de nuevo en unos minutos.',
  error_logged: true
}}];

